import { NavBarRecepcionar } from "./NavBarRecepcionar";
import { Footer } from "./Footer";
import { useState, useRef, useEffect } from "react";
import pattern from "../slike/pattern4.jpg";
import { useNavigate } from "react-router-dom";
export function LoginRecepcionar(){

    const[email,setEmail]=useState("");
    const[lozinkaHash,setLozinka]=useState("");
      const imeRef = useRef(null);

      const navigate=useNavigate();

  useEffect(() => {
    imeRef.current.focus();
  }, []);

const handleSubmit = async (e) => {
  e.preventDefault();

  try {
    const response = await fetch(`http://localhost:8080/receptionists/login/${email}/${lozinkaHash}`, {
      method: "GET"
    });

    if (response.ok) {
  const data = await response.json();
  const receptionist=data.data.receptionist;
//cookie cuvi vrednost u browseru za period koji mu mi zadamo , kad istekne kuki brise se iz browsera
//koristan je zato sto u svakom momentu pamti koji je korisnik trenutno prijavljen i u svakom momentu imamo podatak o korisniku to je id i preko njega
// mozemo da nadjemo korisnika

  // postavljanje cookie-a sa email-om
  document.cookie = `userEmail=${receptionist.korisnickoIme}; path=/;`;

  // ili sa ID-em
  document.cookie = `userId=${receptionist.idRecepcionar}; path=/;`;

  console.log(data);

  navigate("/");
}
 else {
      const data = await response.json();
      alert("Pogresno uneti podaci!");
    }
  } catch (error) {
    console.error("Greska prilikom login-a:", error);
    alert("Server nije dostupan.");
  }
};

return(
    <>
    <NavBarRecepcionar />
    <div style={{ backgroundImage: `url(${pattern})`,
    backgroundSize: "cover",   
    backgroundPosition: "center",
    minHeight: "100vh",         
    display: "flex",
    justifyContent: "center",
    alignItems: "center",
    flexDirection: "column"}}>
    <div className="forma" style={{with:"300px",height:"300px"}}>
        <form onSubmit={handleSubmit}>
   
        <span className="formaSpan">
            Unesite email
            <input type="email" onChange={(e)=>setEmail(e.target.value)} ref={imeRef} required />

        </span>
       <span className="formaSpan">
            Unesite lozinku
            <input type="password" onChange={(e)=>setLozinka(e.target.value)} required/>
        </span>
       <button type="submit" className="btnNav" style={{marginTop:"20px",border: "none",fontSize:"18px",width:"160px",height:"50px"}}>Uloguj se</button>


</form>
        
    </div>
    </div>
    <Footer />
    </>
)


}
